import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface ProfitMarginData {
  currentQuarter: {
    revenue: number;
    expenses: number;
    profit: number;
    profitMarginPercent: number;
  };
  previousQuarter: {
    revenue: number;
    expenses: number;
    profit: number;
    profitMarginPercent: number;
  };
  quarterComparison: {
    quarter: string;
    profitMargin: number;
  }[];
}

export default function Widget() {
  const data = response.data as ProfitMarginData;
  const { currentQuarter, previousQuarter, quarterComparison } = data;
  const isPositiveChange = currentQuarter.profitMarginPercent >= previousQuarter.profitMarginPercent;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: response.meta.theme === 'dark' ? '#1E1E1E' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: response.meta.primaryColor }}>
              Current Quarter
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Revenue: ${currentQuarter.revenue.toLocaleString()}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Expenses: ${currentQuarter.expenses.toLocaleString()}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Profit: ${currentQuarter.profit.toLocaleString()}
            </Typography>
            <Typography variant="body2" sx={{ color: isPositiveChange ? '#4CAF50' : '#FF5722' }}>
              Profit Margin: {currentQuarter.profitMarginPercent}%
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <BarChart
              height={120}
              series={[
                {
                  data: quarterComparison.map(q => q.profitMargin),
                  color: response.meta.accentColor,
                },
              ]}
              xAxis={[
                {
                  data: quarterComparison.map(q => q.quarter),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#B0BEC5',
                  },
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
